#include <bits/stdc++.h>
using namespace std;

typedef long long ll;
typedef vector<ll> vll;

// Multiply two N x N matrices over GF(2)
vector<vll> mat_mul(const vector<vll>& a, const vector<vll>& b, int n) {
    vector<vll> c(n, vll(n, 0));
    for (int i = 0; i < n; i++) {
        for (int k = 0; k < n; k++) {
            if (a[i][k] == 0) continue;
            for (int j = 0; j < n; j++) {
                c[i][j] ^= (a[i][k] & b[k][j]);
            }
        }
    }
    return c;
}

// Multiply matrix by vector over GF(2)
vll mat_vec_mul(const vector<vll>& mat, const vll& vec, int n) {
    vll res(n, 0);
    for (int i = 0; i < n; i++) {
        ll sum = 0;
        for (int j = 0; j < n; j++) {
            sum ^= (mat[i][j] & vec[j]);
        }
        res[i] = sum;
    }
    return res;
}

// Matrix exponentiation over GF(2)
vector<vll> mat_pow(vector<vll> a, ll e, int n) {
    vector<vll> res(n, vll(n, 0));
    for (int i = 0; i < n; i++) res[i][i] = 1;
    while (e > 0) {
        if (e & 1) res = mat_mul(res, a, n);
        a = mat_mul(a, a, n);
        e >>= 1;
    }
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    ll B;
    int N;
    cin >> B >> N;

    vll init(N);
    for (int i = 0; i < N; i++) {
        cin >> init[i];
    }

    // Build transition matrix T over GF(2)
    // new_state[i] = old_state[i] XOR old_state[(i-1) mod N]
    // So T[i][i] = 1, T[i][(i-1+N)%N] = 1
    vector<vll> T(N, vll(N, 0));
    for (int i = 0; i < N; i++) {
        T[i][i] = 1;
        T[i][(i - 1 + N) % N] = 1;
    }

    // Compute T^B
    vector<vll> TB = mat_pow(T, B, N);

    // Multiply by initial vector
    vll ans = mat_vec_mul(TB, init, N);

    for (int i = 0; i < N; i++) {
        if (i) cout << ' ';
        cout << ans[i];
    }
    cout << '\n';

    return 0;
}
